import { assignChecks } from "./menuOptions";
import type {
	IData,
	IDataHash,
	IParsedTask,
	IHistory,
	IDataConfig,
} from "../types";
import type { TID } from "@svar-ui/lib-state";

export function getToolbarButtons(config?: IDataConfig) {
	let buttons = [...defaultToolbarButtons];

	// #if [!(WX_PACKAGE_TYPE=open)]
	if (config?.undo) {
		buttons = buttons.concat([
			{ comp: "separator" },
			{
				id: "undo",
				comp: "icon",
				icon: "wxi-undo",
				menuText: "Undo",
			},
			{
				id: "redo",
				comp: "icon",
				icon: "wxi-redo",
				menuText: "Redo",
			},
		]);
	}
	if (config?.splitTasks) {
		buttons.splice(2, 0, {
			id: "split-task",
			comp: "icon",
			icon: "wxi-arrow-split",
			menuText: "Split",
		});
	}
	if (buttons.length > defaultToolbarButtons.length)
		buttons = assignChecks(buttons);
	// #endif
	return buttons;
}

export interface IButtonConfig {
	id?: string;
	comp: string;
	text?: string;
	icon?: string;
	type?: string;
	menuText?: string;
	isDisabled?:
		| ((
				task: IParsedTask,
				state: IData,
				target?: TID | IDataHash
		  ) => boolean)
		| ((history: IHistory) => boolean);
	isHidden?: (
		task: IParsedTask,
		state: IData,
		target?: TID | IDataHash
	) => boolean;
}

